-- =========================================================
-- Pupoo Database Seed Data v5.2 (realistic local dataset)
-- =========================================================
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- 1) users (101)

-- 2) social_account (100)

-- 3) pet (100)

-- 4) event (100)

-- 5) event_images (100)

-- 6) event_apply (100)

-- 7) booths (100)

-- 8) event_program (100)

-- 9) event_program_apply (100)

-- 10) boards

-- 11) posts (100)

-- 12) files (100)

-- 13) notices (100)

-- 14) galleries (100)

-- 15) gallery_images (300)

-- 16) gallery_likes (100)

-- 17) reviews (100)

-- 18) inquiries (100)

-- 19) inquiry_answers (100)

-- 20) admin_logs (100)

-- 21) refresh_token (100)

-- =========================================================
-- v5.2 1-year operation extension seed (2025-03-01 ~ 2026-03-01)
-- =========================================================

DROP TEMPORARY TABLE IF EXISTS tmp_nums;
CREATE TEMPORARY TABLE tmp_nums (n INT PRIMARY KEY);
SELECT ones.n + tens.n * 10 + hundreds.n * 100 + 1 AS n
FROM
  (SELECT 0 n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9) ones
CROSS JOIN
  (SELECT 0 n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9) tens
CROSS JOIN
  (SELECT 0 n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9) hundreds;

-- 22) speakers (120)
SELECT CONCAT('Speaker ', LPAD(n, 3, '0')),
       CONCAT('Session specialist #', LPAD(n, 3, '0')),
       CONCAT('speaker', LPAD(n, 3, '0'), '@pupoo.io'),
       CONCAT('02-700-', LPAD(n, 4, '0')),
       DATE_ADD('2025-03-01 09:00:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 120;

SELECT n, n, DATE_ADD('2025-03-01 10:00:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 100;

SELECT n, 5 + (n % 70), 2 + (n % 25), DATE_ADD('2026-02-01 09:00:00', INTERVAL n HOUR)
FROM tmp_nums WHERE n <= 100;

SELECT n, 3 + (n % 50), 1 + (n % 18), DATE_ADD('2026-02-01 10:00:00', INTERVAL n HOUR)
FROM tmp_nums WHERE n <= 100;

SELECT ((n - 1) % 100) + 1,
       ELT(((n - 1) % 4) + 1, 'ZONE_A','ZONE_B','ZONE_C','OTHER'),
       CONCAT('Zone spot ', LPAD(((n - 1) % 100) + 1, 3, '0')),
       ((n - 1) % 5) + 1,
       DATE_ADD('2025-03-01 09:00:00', INTERVAL n HOUR)
FROM tmp_nums WHERE n <= 300;

SELECT ((n - 1) % 100) + 2,
       ((n - 1) % 100) + 1,
       ((n - 1) % 100) + 1,
       DATE_ADD('2025-03-01 11:00:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 400;

SELECT n + 1, n, 1 + (n % 12), DATE_ADD('2026-02-20 08:00:00', INTERVAL n HOUR)
FROM tmp_nums WHERE n <= 100;

SELECT n, n, ((n + 20) % 100) + 2, DATE_ADD('2025-08-01 10:00:00', INTERVAL n DAY), 'ACTIVE', NULL
FROM tmp_nums WHERE n <= 100;

SELECT ((n - 1) % 100) + 1,
       ((n + 10) % 100) + 2,
       CONCAT('Post comment ', LPAD(n, 3, '0')),
       DATE_ADD('2025-03-01 13:00:00', INTERVAL n DAY),
       DATE_ADD('2025-03-01 13:30:00', INTERVAL n DAY),
       0
FROM tmp_nums WHERE n <= 300;

SELECT ((n - 1) % 3) + 1,
       CONCAT('ban_word_', LPAD(n, 2, '0')),
       DATE_ADD('2025-03-01 14:00:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 30;

  reporter_user_id, target_type, target_id, reason_code, reason_detail, reason,
  status, created_at, resolved_at, resolved_by_admin_id
)
SELECT ((n - 1) % 100) + 2,
       ELT(((n - 1) % 4) + 1, 'POST','REVIEW','POST_COMMENT','REVIEW_COMMENT'),
       n,
       ELT(((n - 1) % 9) + 1, 'SPAM','ABUSE','HATE','SEXUAL','VIOLENCE','PRIVACY','FRAUD','COPYRIGHT','OTHER'),
       CONCAT('detail-', n),
       CONCAT('report reason ', n),
       ELT(((n - 1) % 3) + 1, 'PENDING','ACCEPTED','REJECTED'),
       DATE_ADD('2025-04-01 11:00:00', INTERVAL n DAY),
       CASE WHEN (n % 3) = 1 THEN DATE_ADD('2025-04-02 11:00:00', INTERVAL n DAY) ELSE NULL END,
       CASE WHEN (n % 3) = 1 THEN 1 ELSE NULL END
FROM tmp_nums WHERE n <= 100;

SELECT ((n - 1) % 100) + 1,
       ((n + 30) % 100) + 2,
       CONCAT('Review comment ', LPAD(n, 3, '0')),
       DATE_ADD('2025-03-10 15:00:00', INTERVAL n DAY),
       DATE_ADD('2025-03-10 16:00:00', INTERVAL n DAY),
       0
FROM tmp_nums WHERE n <= 200;

SELECT n + 1,
       n,
       n,
       CONCAT('ORD-2025-', LPAD(n, 5, '0')),
       CASE WHEN (n % 5) = 0 THEN 25000.00 WHEN (n % 3) = 0 THEN 15000.00 ELSE 10000.00 END,
       'KAKAOPAY',
       ELT(((n - 1) % 3) + 1, 'APPROVED','FAILED','CANCELLED'),
       DATE_ADD('2025-03-01 09:00:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 100;

  payment_id, pg_provider, pg_tid, pg_token, status, idempotency_key,
  raw_ready, raw_approve, raw_cancel, requested_at, approved_at, cancelled_at, failed_at, created_at, updated_at
)
SELECT n,
       'KAKAOPAY',
       CONCAT('TID-2025-', LPAD(n, 6, '0')),
       CONCAT('PGTK-', LPAD(n, 6, '0')),
       CASE WHEN (n % 3) = 1 THEN 'APPROVED' WHEN (n % 3) = 2 THEN 'FAILED' ELSE 'CANCELLED' END,
       CONCAT('idem-', LPAD(n, 6, '0')),
       JSON_OBJECT('step','ready','n',n),
       CASE WHEN (n % 3) = 1 THEN JSON_OBJECT('step','approve','n',n) ELSE NULL END,
       CASE WHEN (n % 3) = 0 THEN JSON_OBJECT('step','cancel','n',n) ELSE NULL END,
       DATE_ADD('2025-03-01 09:05:00', INTERVAL n DAY),
       CASE WHEN (n % 3) = 1 THEN DATE_ADD('2025-03-01 09:10:00', INTERVAL n DAY) ELSE NULL END,
       CASE WHEN (n % 3) = 0 THEN DATE_ADD('2025-03-01 09:15:00', INTERVAL n DAY) ELSE NULL END,
       CASE WHEN (n % 3) = 2 THEN DATE_ADD('2025-03-01 09:20:00', INTERVAL n DAY) ELSE NULL END,
       DATE_ADD('2025-03-01 09:05:00', INTERVAL n DAY),
       DATE_ADD('2025-03-01 09:25:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 100;

SELECT n,
       5000.00 + (n * 100),
       CONCAT('refund reason ', n),
       CASE WHEN (n % 3) = 0 THEN 'COMPLETED' WHEN (n % 3) = 1 THEN 'REQUESTED' ELSE 'REJECTED' END,
       DATE_ADD('2025-06-01 10:00:00', INTERVAL n DAY),
       CASE WHEN (n % 3) = 0 THEN DATE_ADD('2025-06-03 10:00:00', INTERVAL n DAY) ELSE NULL END,
       DATE_ADD('2025-06-01 10:00:00', INTERVAL n DAY),
       DATE_ADD('2025-06-04 10:00:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 20;

SELECT n + 1,
       n,
       CONCAT('/static/qr/qr-', LPAD(n, 4, '0'), '.png'),
       'png',
       DATE_ADD('2025-03-01 08:00:00', INTERVAL n DAY),
       DATE_ADD('2026-03-01 00:00:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 100;

SELECT ((n - 1) % 100) + 1,
       ((n + 4) % 100) + 1,
       IF((n % 2) = 0, 'CHECKIN', 'CHECKOUT'),
       DATE_ADD('2025-03-01 08:30:00', INTERVAL n HOUR)
FROM tmp_nums WHERE n <= 300;

SELECT ELT(((n - 1) % 5) + 1, 'EVENT','NOTICE','PAYMENT','APPLY','SYSTEM'),
       CONCAT('Notification title ', LPAD(n, 3, '0')),
       CONCAT('Notification content ', LPAD(n, 3, '0')),
       DATE_ADD('2025-03-01 07:00:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 240;

SELECT n,
       CASE WHEN (n % 4) = 0 THEN 1 ELSE ((n - 1) % 100) + 2 END,
       CASE WHEN (n % 4) = 0 THEN 'ADMIN' ELSE 'SYSTEM' END,
       ELT(((n - 1) % 4) + 1, 'APP','EMAIL','SMS','PUSH'),
       DATE_ADD('2025-03-01 07:10:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 240;

SELECT ((n - 1) % 100) + 2,
       ((n - 1) % 240) + 1,
       DATE_ADD('2025-03-01 07:20:00', INTERVAL n HOUR),
       CASE WHEN (n % 2) = 0 THEN 'EVENT' ELSE 'NOTICE' END,
       ((n - 1) % 100) + 1
FROM tmp_nums WHERE n <= 600;

SELECT n, IF((n % 3) = 0, 0, 1), DATE_ADD('2025-03-01 06:00:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 101;


  user_id, interest_id, allow_inapp, allow_email, allow_sms, status, created_at
)
SELECT n + 1,
       ((n - 1) % 17) + 1,
       1,
       IF((n % 2)=0,1,0),
       IF((n % 5)=0,1,0),
       ELT(((n - 1) % 3) + 1, 'ACTIVE','PAUSED','CANCELLED'),
       DATE_ADD('2025-03-01 05:00:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 100;

SELECT n,
       ((n - 1) % 17) + 1,
       DATE_ADD('2025-03-01 04:00:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 100;

SELECT n + 1,
       CONCAT('evt_hash_', LPAD(n, 4, '0')),
       DATE_ADD('2026-03-01 00:00:00', INTERVAL n DAY),
       CASE WHEN (n % 4) = 0 THEN DATE_ADD('2025-03-05 00:00:00', INTERVAL n DAY) ELSE NULL END,
       DATE_ADD('2025-03-01 03:00:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 100;

SELECT n + 1,
       CONCAT('010-', LPAD(1000 + n, 4, '0'), '-', LPAD(2000 + n, 4, '0')),
       CONCAT('pvt_hash_', LPAD(n, 4, '0')),
       DATE_ADD('2026-03-01 00:00:00', INTERVAL n DAY),
       CASE WHEN (n % 5) = 0 THEN DATE_ADD('2025-03-03 00:00:00', INTERVAL n DAY) ELSE NULL END,
       (n % 3),
       DATE_ADD('2025-03-01 02:00:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 100;

  signup_key, signup_type, social_provider, social_provider_uid,
  email, password_hash, nickname, phone,
  otp_status, otp_verified_at, otp_last_sent_at, otp_code_hash, otp_expires_at, otp_fail_count, otp_blocked_until,
  email_status, email_verified_at, email_code_hash, email_expires_at, email_last_sent_at, email_fail_count,
  expires_at, created_at, updated_at
)
SELECT CONCAT('sess-', LPAD(n, 6, '0')),
       IF((n % 2)=0, 'EMAIL', 'SOCIAL'),
       CASE WHEN (n % 2)=0 THEN NULL ELSE ELT(((n - 1) % 4) + 1, 'KAKAO','NAVER','GOOGLE','APPLE') END,
       CASE WHEN (n % 2)=0 THEN NULL ELSE CONCAT('social_uid_', LPAD(n, 6, '0')) END,
       CONCAT('prospect', LPAD(n, 4, '0'), '@pupoo.io'),
       CONCAT('pw_hash_', LPAD(n, 6, '0')),
       CONCAT('signup_user_', LPAD(n, 4, '0')),
       CONCAT('010-8', LPAD(n, 3, '0'), '-', LPAD(3000 + n, 4, '0')),
       ELT(((n - 1) % 3) + 1, 'PENDING','VERIFIED','EXPIRED'),
       CASE WHEN (n % 3)=2 THEN DATE_ADD('2025-03-02 00:00:00', INTERVAL n DAY) ELSE NULL END,
       DATE_ADD('2025-03-01 01:00:00', INTERVAL n DAY),
       CONCAT('otp_hash_', LPAD(n, 6, '0')),
       DATE_ADD('2025-03-01 01:10:00', INTERVAL n DAY),
       (n % 4),
       CASE WHEN (n % 7)=0 THEN DATE_ADD('2025-03-01 01:20:00', INTERVAL n DAY) ELSE NULL END,
       ELT(((n - 1) % 3) + 1, 'PENDING','VERIFIED','NOT_REQUIRED'),
       CASE WHEN (n % 3)=2 THEN DATE_ADD('2025-03-02 00:30:00', INTERVAL n DAY) ELSE NULL END,
       CONCAT('email_hash_', LPAD(n, 6, '0')),
       DATE_ADD('2025-03-01 01:40:00', INTERVAL n DAY),
       DATE_ADD('2025-03-01 01:30:00', INTERVAL n DAY),
       (n % 2),
       DATE_ADD('2025-03-15 00:00:00', INTERVAL n DAY),
       DATE_ADD('2025-03-01 01:00:00', INTERVAL n DAY),
       DATE_ADD('2025-03-01 01:50:00', INTERVAL n DAY)
FROM tmp_nums WHERE n <= 120;

DROP TEMPORARY TABLE IF EXISTS tmp_nums;

SET FOREIGN_KEY_CHECKS = 1;